class Solution {
    public int[] pivotArray(int[] nums, int pivot) {
        int n = nums.length;
        int[] less = new int[n];
        int[] equal = new int[n];
        int[] greater = new int[n];
        int lessIndex = 0, equalIndex = 0, greaterIndex = 0;

        for (int num : nums) {
            if (num < pivot) {
                less[lessIndex++] = num;
            } else if (num == pivot) {
                equal[equalIndex++] = num;
            } else {
                greater[greaterIndex++] = num;
            }
        }

        int[] result = new int[n];
        System.arraycopy(less, 0, result, 0, lessIndex);
        System.arraycopy(equal, 0, result, lessIndex, equalIndex);
        System.arraycopy(greater, 0, result, lessIndex + equalIndex, greaterIndex);

        return result;
    }
}
```

